import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useSlides } from "../contexts/SlideContext";
import { useToast } from "../contexts/ToastContext";
import { Slide, ImageSlide, VideoSlide, SLIDE_TYPES, ImageSlideData, VideoSlideData } from "../types";

/** Configuration for the backend API URL */
const BACKEND_URL = process.env.REACT_APP_BACKEND_URL || "http://localhost:5000";

/** Type for form validation errors */
interface FormErrors {
    name?: string;
    imageUrl?: string;
    videoUrl?: string;
    caption?: string;
    duration?: string;
}

/** Interface for slide type card properties */
interface SlideTypeCard {
    type: typeof SLIDE_TYPES[keyof typeof SLIDE_TYPES];
    title: string;
    description: string;
    icon: React.ReactNode;
}

/** Props for the edit modal component */
interface EditModalProps {
    isOpen: boolean;
    onClose: () => void;
    slide: ImageSlide | VideoSlide | null;
    onSave: (slide: ImageSlide | VideoSlide) => void;
}

/** Props for the slide preview component */
interface SlidePreviewProps {
    slide: ImageSlide;
    onEdit: (slide: ImageSlide) => void;
    onDelete: (id: string) => void;
    onToggleActive: (id: string, active: boolean) => void;
}

/** Type for the image upload response */
interface ImageUploadResponse {
    url: string;
    success: boolean;
    error?: string;
}

/** Function to get the API URL based on environment */
const getApiUrl = (): string => {
    return process.env.NODE_ENV === "development"
        ? `${BACKEND_URL}/api/upload`
        : "/api/upload";
};

const SLIDE_TYPE_CARDS: SlideTypeCard[] = [
    {
        type: SLIDE_TYPES.IMAGE,
        title: "Image Slider",
        description: "Create a slideshow with images and optional captions",
        icon: (
            <svg
                className="w-8 h-8"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
            >
                <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth="2"
                    d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
                />
            </svg>
        ),
    },
    {
        type: SLIDE_TYPES.VIDEO,
        title: "Video Slider",
        description: "Create a slideshow with videos and optional captions",
        icon: (
            <svg
                className="w-8 h-8"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
            >
                <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth="2"
                    d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z"
                />
            </svg>
        ),
    },
];

const EditModal: React.FC<EditModalProps> = ({ isOpen, onClose, slide, onSave }) => {
    const { addToast } = useToast();
    const [editedSlide, setEditedSlide] = useState<ImageSlide | VideoSlide | null>(slide);
    const [pendingImageFile, setPendingImageFile] = useState<File | null>(null);
    const [imagePreviewUrl, setImagePreviewUrl] = useState<string>(slide?.data.imageUrl || "");
    const [isUploading, setIsUploading] = useState<boolean>(false);
    const [errors, setErrors] = useState<FormErrors>({});

    /** Validates the form and returns true if valid */
    const validateForm = (): boolean => {
        const newErrors: FormErrors = {};

        if (!editedSlide?.name?.trim()) {
            newErrors.name = "Slide name is required";
        }

        if (!editedSlide?.data.imageUrl && !editedSlide?.data.videoUrl) {
            newErrors.imageUrl = "Image or video is required";
        }

        if (editedSlide?.duration && (editedSlide.duration < 1 || editedSlide.duration > 60)) {
            newErrors.duration = "Duration must be between 1 and 60 seconds";
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const handleFileInput = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) {
            setImagePreviewUrl("");
            setPendingImageFile(null);
            return;
        }

        // Validate file type and size
        if (!file.type.startsWith("image/") && !file.type.startsWith("video/")) {
            addToast("Please upload an image or video file", "error");
            return;
        }

        if (file.size > 5 * 1024 * 1024) { // 5MB limit
            addToast("File size should be less than 5MB", "error");
            return;
        }

        setPendingImageFile(file);
        setIsUploading(true);
        setErrors((prev) => ({ ...prev, imageUrl: undefined, videoUrl: undefined }));

        const formData = new FormData();
        formData.append("file", file);

        try {
            const res = await fetch(getApiUrl(), {
                method: "POST",
                body: formData
            });
            const data: ImageUploadResponse = await res.json();

            if (data.success && data.url) {
                const imageUrl = data.url.startsWith("http")
                    ? data.url
                    : `${BACKEND_URL}${data.url}`;
                setImagePreviewUrl(imageUrl);
                setEditedSlide((prev) =>
                    prev
                        ? {
                            ...prev,
                            data: {
                                ...prev.data,
                                imageUrl,
                                videoUrl: "",
                            },
                        }
                        : null
                );
                addToast("Image uploaded successfully", "success");
            } else {
                throw new Error(data.error || "Upload failed");
            }
        } catch (err) {
            setImagePreviewUrl("");
            addToast(err instanceof Error ? err.message : "Upload failed", "error");
            setErrors((prev) => ({ ...prev, imageUrl: "Failed to upload image", videoUrl: "Failed to upload video" }));
        } finally {
            setIsUploading(false);
        }
    };

    const handleSave = () => {
        if (!editedSlide || !validateForm()) {
            return;
        }
        onSave(editedSlide);
        onClose();
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === "Escape") {
            onClose();
        } else if (e.key === "Enter" && e.ctrlKey) {
            handleSave();
        }
    };

    if (!isOpen) return null;

    return (
        <div
            className="fixed inset-0 bg-black/50 flex items-center justify-center z-50"
            role="dialog"
            aria-modal="true"
            aria-labelledby="modal-title"
            onKeyDown={handleKeyDown}
        >
            <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className="bg-white rounded-xl shadow-xl w-full max-w-2xl p-6"
            >
                <div className="flex items-center justify-between mb-6">
                    <h2 id="modal-title" className="text-2xl font-bold text-gray-900">
                        {slide ? "Edit" : "Create"} Slide
                    </h2>
                    <button
                        onClick={onClose}
                        className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
                        aria-label="Close modal"
                    >
                        <svg
                            className="w-6 h-6"
                            fill="none"
                            stroke="currentColor"
                            viewBox="0 0 24 24"
                        >
                            <path
                                strokeLinecap="round"
                                strokeLinejoin="round"
                                strokeWidth="2"
                                d="M6 18L18 6M6 6l12 12"
                            />
                        </svg>
                    </button>
                </div>

                <div className="space-y-4">
                    <div>
                        <label htmlFor="slideName" className="block text-sm font-medium text-gray-700 mb-1">
                            Slide Name *
                        </label>
                        <input
                            id="slideName"
                            type="text"
                            value={editedSlide?.name || ""}
                            onChange={(e) =>
                                setEditedSlide((prev) =>
                                    prev
                                        ? {
                                            ...prev,
                                            name: e.target.value,
                                        }
                                        : null
                                )
                            }
                            className={`w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 ${errors.name ? "border-red-500" : "border-gray-300"
                                }`}
                            placeholder="Enter slide name"
                            aria-invalid={Boolean(errors.name)}
                            aria-describedby={errors.name ? "name-error" : undefined}
                        />
                        {errors.name && (
                            <p id="name-error" className="mt-1 text-sm text-red-500">
                                {errors.name}
                            </p>
                        )}
                    </div>

                    <div>
                        <label htmlFor="imageUpload" className="block text-sm font-medium text-gray-700 mb-1">
                            Upload Image *
                        </label>
                        <input
                            id="imageUpload"
                            type="file"
                            accept="image/*"
                            onChange={handleFileInput}
                            className={`w-full px-3 py-2 border rounded-lg file:mr-4 file:py-2 file:px-4
                                file:rounded-full file:border-0 file:text-sm file:font-semibold
                                file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100 ${errors.imageUrl ? "border-red-500" : "border-gray-300"
                                }`}
                            disabled={isUploading}
                            aria-invalid={Boolean(errors.imageUrl)}
                            aria-describedby={errors.imageUrl ? "image-error" : undefined}
                        />
                        {errors.imageUrl && (
                            <p id="image-error" className="mt-1 text-sm text-red-500">
                                {errors.imageUrl}
                            </p>
                        )}
                        {isUploading && (
                            <div className="mt-2 flex items-center text-sm text-gray-500">
                                <svg className="animate-spin h-5 w-5 mr-2" viewBox="0 0 24 24">
                                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                                </svg>
                                Uploading image...
                            </div>
                        )}
                        {imagePreviewUrl && (
                            <div className="mt-2">
                                <img
                                    src={imagePreviewUrl}
                                    alt="Preview"
                                    className="max-h-48 rounded-lg object-contain"
                                />
                            </div>
                        )}
                    </div>

                    <div>
                        <label htmlFor="videoUpload" className="block text-sm font-medium text-gray-700 mb-1">
                            Upload Video *
                        </label>
                        <input
                            id="videoUpload"
                            type="file"
                            accept="video/*"
                            onChange={handleFileInput}
                            className={`w-full px-3 py-2 border rounded-lg file:mr-4 file:py-2 file:px-4
                                file:rounded-full file:border-0 file:text-sm file:font-semibold
                                file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100 ${errors.videoUrl ? "border-red-500" : "border-gray-300"
                                }`}
                            disabled={isUploading}
                            aria-invalid={Boolean(errors.videoUrl)}
                            aria-describedby={errors.videoUrl ? "video-error" : undefined}
                        />
                        {errors.videoUrl && (
                            <p id="video-error" className="mt-1 text-sm text-red-500">
                                {errors.videoUrl}
                            </p>
                        )}
                        {isUploading && (
                            <div className="mt-2 flex items-center text-sm text-gray-500">
                                <svg className="animate-spin h-5 w-5 mr-2" viewBox="0 0 24 24">
                                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                                </svg>
                                Uploading video...
                            </div>
                        )}
                        {imagePreviewUrl && (
                            <div className="mt-2">
                                <img
                                    src={imagePreviewUrl}
                                    alt="Preview"
                                    className="max-h-48 rounded-lg object-contain"
                                />
                            </div>
                        )}
                    </div>

                    <div>
                        <label htmlFor="caption" className="block text-sm font-medium text-gray-700 mb-1">
                            Caption
                        </label>
                        <input
                            id="caption"
                            type="text"
                            value={editedSlide?.data.caption || ""}
                            onChange={(e) =>
                                setEditedSlide((prev) =>
                                    prev
                                        ? {
                                            ...prev,
                                            data: {
                                                ...prev.data,
                                                caption: e.target.value,
                                            },
                                        }
                                        : null
                                )
                            }
                            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                            placeholder="Image caption or description"
                        />
                    </div>

                    <div>
                        <label htmlFor="duration" className="block text-sm font-medium text-gray-700 mb-1">
                            Duration (seconds) *
                        </label>
                        <input
                            id="duration"
                            type="number"
                            value={editedSlide?.duration || 5}
                            onChange={(e) =>
                                setEditedSlide((prev) =>
                                    prev
                                        ? {
                                            ...prev,
                                            duration: Math.max(1, Math.min(60, Number(e.target.value))),
                                        }
                                        : null
                                )
                            }
                            min="1"
                            max="60"
                            className={`w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 ${errors.duration ? "border-red-500" : "border-gray-300"
                                }`}
                            aria-invalid={Boolean(errors.duration)}
                            aria-describedby={errors.duration ? "duration-error" : undefined}
                        />
                        {errors.duration && (
                            <p id="duration-error" className="mt-1 text-sm text-red-500">
                                {errors.duration}
                            </p>
                        )}
                    </div>

                    <div>
                        <label className="flex items-center space-x-2">
                            <input
                                type="checkbox"
                                checked={editedSlide?.active || false}
                                onChange={(e) =>
                                    setEditedSlide((prev) =>
                                        prev
                                            ? {
                                                ...prev,
                                                active: e.target.checked,
                                            }
                                            : null
                                    )
                                }
                                className="w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
                            />
                            <span className="text-sm font-medium text-gray-700">Active</span>
                        </label>
                    </div>

                    <div className="flex justify-end space-x-3 mt-6">
                        <button
                            type="button"
                            onClick={onClose}
                            className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                        >
                            Cancel
                        </button>
                        <button
                            type="button"
                            onClick={handleSave}
                            disabled={isUploading}
                            className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            {isUploading ? "Uploading..." : "Save"}
                        </button>
                    </div>
                </div>
            </motion.div>
        </div>
    );
};

const AdminPage: React.FC = () => {
    const { slides, addSlide, updateSlide, deleteSlide } = useSlides();
    const { addToast } = useToast();
    const [selectedSlide, setSelectedSlide] = useState<ImageSlide | VideoSlide | null>(null);
    const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
    const [isDeleting, setIsDeleting] = useState<boolean>(false);
    const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

    const imageSlides = slides.filter((slide): slide is ImageSlide => slide.type === SLIDE_TYPES.IMAGE);
    const videoSlides = slides.filter((slide): slide is VideoSlide => slide.type === SLIDE_TYPES.VIDEO);
    const activeSlides = imageSlides.filter((slide) => slide.active);
    const inactiveSlides = imageSlides.filter((slide) => !slide.active);

    const handleCreateSlide = (type: typeof SLIDE_TYPES[keyof typeof SLIDE_TYPES]) => {
        if (type === SLIDE_TYPES.IMAGE) {
            const newSlide: ImageSlide = {
                id: crypto.randomUUID(),
                type,
                name: "",
                active: true,
                duration: 5,
                data: {
                    imageUrl: "",
                    caption: "",
                },
                dataSource: "manual"
            };
            setSelectedSlide(newSlide);
        } else if (type === SLIDE_TYPES.VIDEO) {
            const newSlide: VideoSlide = {
                id: crypto.randomUUID(),
                type,
                name: "",
                active: true,
                duration: 5,
                data: {
                    videoUrl: "",
                    caption: "",
                    autoplay: true,
                    muted: true,
                    loop: true
                },
                dataSource: "manual"
            };
            setSelectedSlide(newSlide);
        }
        setIsModalOpen(true);
    };

    const handleEditSlide = (slide: ImageSlide | VideoSlide) => {
        setSelectedSlide(slide);
        setIsModalOpen(true);
    };

    const handleSaveSlide = async (updatedSlide: ImageSlide | VideoSlide) => {
        try {
            if (selectedSlide?.id) {
                await updateSlide(updatedSlide);
                addToast("Slide updated successfully", "success");
            } else {
                await addSlide(updatedSlide);
                addToast("Slide created successfully", "success");
            }
            setIsModalOpen(false);
            setSelectedSlide(null);
        } catch (error) {
            addToast(error instanceof Error ? error.message : "Failed to save slide", "error");
        }
    };

    const handleDeleteSlide = async (id: string) => {
        setIsDeleting(true);
        try {
            await deleteSlide(id);
            addToast("Slide deleted successfully", "success");
            setDeleteConfirmId(null);
        } catch (error) {
            addToast(error instanceof Error ? error.message : "Failed to delete slide", "error");
        } finally {
            setIsDeleting(false);
        }
    };

    const handleToggleActive = async (id: string, active: boolean) => {
        const slide = slides.find((s) => s.id === id);
        if (slide) {
            try {
                await updateSlide({ ...slide, active });
                addToast(`Slide ${active ? "activated" : "deactivated"} successfully`, "success");
            } catch (error) {
                addToast(error instanceof Error ? error.message : "Failed to update slide status", "error");
            }
        }
    };

    return (
        <div className="container mx-auto px-4 py-8">
            <div className="flex justify-between items-center mb-8">
                <h1 className="text-3xl font-bold text-gray-900">Slide Management</h1>
                <button
                    onClick={() => handleCreateSlide(SLIDE_TYPES.IMAGE)}
                    className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                >
                    Create New Slide
                </button>
            </div>

            {/* Active Slides Section */}
            <section className="mb-8">
                <h2 className="text-xl font-semibold text-gray-900 mb-4">Active Slides</h2>
                {activeSlides.length === 0 ? (
                    <p className="text-gray-500 text-center py-8 bg-gray-50 rounded-lg">
                        No active slides. Create a new slide to get started.
                    </p>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {activeSlides.map((slide) => (
                            <SlideCard
                                key={slide.id}
                                slide={slide}
                                onEdit={handleEditSlide}
                                onDelete={(id) => setDeleteConfirmId(id)}
                                onToggleActive={handleToggleActive}
                            />
                        ))}
                    </div>
                )}
            </section>

            {/* Inactive Slides Section */}
            {inactiveSlides.length > 0 && (
                <section>
                    <h2 className="text-xl font-semibold text-gray-900 mb-4">Inactive Slides</h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {inactiveSlides.map((slide) => (
                            <SlideCard
                                key={slide.id}
                                slide={slide}
                                onEdit={handleEditSlide}
                                onDelete={(id) => setDeleteConfirmId(id)}
                                onToggleActive={handleToggleActive}
                            />
                        ))}
                    </div>
                </section>
            )}

            {/* Edit Modal */}
            <EditModal
                isOpen={isModalOpen}
                onClose={() => {
                    setIsModalOpen(false);
                    setSelectedSlide(null);
                }}
                slide={selectedSlide}
                onSave={handleSaveSlide}
            />

            {/* Delete Confirmation Modal */}
            <AnimatePresence>
                {deleteConfirmId && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 bg-black/50 flex items-center justify-center z-50"
                    >
                        <div className="bg-white rounded-lg p-6 max-w-md w-full mx-4">
                            <h3 className="text-lg font-semibold text-gray-900 mb-4">
                                Confirm Delete
                            </h3>
                            <p className="text-gray-600 mb-6">
                                Are you sure you want to delete this slide? This action cannot be undone.
                            </p>
                            <div className="flex justify-end space-x-3">
                                <button
                                    onClick={() => setDeleteConfirmId(null)}
                                    className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                                    disabled={isDeleting}
                                >
                                    Cancel
                                </button>
                                <button
                                    onClick={() => deleteConfirmId && handleDeleteSlide(deleteConfirmId)}
                                    className="px-4 py-2 text-sm font-medium text-white bg-red-600 rounded-lg hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 disabled:opacity-50"
                                    disabled={isDeleting}
                                >
                                    {isDeleting ? "Deleting..." : "Delete"}
                                </button>
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

/** Props for the slide card component */
interface SlideCardProps {
    slide: ImageSlide | VideoSlide;
    onEdit: (slide: ImageSlide | VideoSlide) => void;
    onDelete: (id: string) => void;
    onToggleActive: (id: string, active: boolean) => void;
}

/** Component for displaying a single slide card */
const SlideCard: React.FC<SlideCardProps> = ({ slide, onEdit, onDelete, onToggleActive }) => {
    const [mediaError, setMediaError] = useState<boolean>(false);

    const isVideoSlide = slide.type === SLIDE_TYPES.VIDEO;
    const mediaUrl = isVideoSlide ? (slide as VideoSlide).data.videoUrl : (slide as ImageSlide).data.imageUrl;

    return (
        <motion.div
            layout
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="bg-white rounded-lg shadow-md overflow-hidden"
        >
            <div className="aspect-video relative bg-gray-100">
                {!mediaError ? (
                    isVideoSlide ? (
                        <video
                            src={mediaUrl}
                            className="w-full h-full object-cover"
                            onError={() => setMediaError(true)}
                            controls
                            muted
                        />
                    ) : (
                        <img
                            src={mediaUrl}
                            alt={slide.name}
                            className="w-full h-full object-cover"
                            onError={() => setMediaError(true)}
                        />
                    )
                ) : (
                    <div className="w-full h-full flex items-center justify-center text-gray-400">
                        <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path
                                strokeLinecap="round"
                                strokeLinejoin="round"
                                strokeWidth="2"
                                d={isVideoSlide
                                    ? "M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z"
                                    : "M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
                                }
                            />
                        </svg>
                    </div>
                )}
            </div>

            <div className="p-4">
                <div className="flex items-start justify-between mb-2">
                    <h3 className="font-medium text-gray-900 truncate" title={slide.name}>
                        {slide.name || "Untitled Slide"}
                    </h3>
                    <span
                        className={`px-2 py-1 text-xs font-medium rounded-full ${slide.active
                            ? "bg-green-100 text-green-800"
                            : "bg-gray-100 text-gray-800"
                            }`}
                    >
                        {slide.active ? "Active" : "Inactive"}
                    </span>
                </div>

                {slide.data.caption && (
                    <p className="text-sm text-gray-600 mb-3 line-clamp-2" title={slide.data.caption}>
                        {slide.data.caption}
                    </p>
                )}

                <div className="flex items-center justify-between mt-4">
                    <div className="text-sm text-gray-500">
                        Duration: {slide.duration}s
                    </div>
                    <div className="flex items-center space-x-2">
                        <button
                            onClick={() => onToggleActive(slide.id, !slide.active)}
                            className="p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                            title={slide.active ? "Deactivate" : "Activate"}
                        >
                            <svg
                                className="w-5 h-5"
                                fill="none"
                                stroke="currentColor"
                                viewBox="0 0 24 24"
                            >
                                <path
                                    strokeLinecap="round"
                                    strokeLinejoin="round"
                                    strokeWidth="2"
                                    d={
                                        slide.active
                                            ? "M10 9v6m4-6v6m7-3a9 9 0 11-18 0 9 9 0 0118 0z"
                                            : "M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z"
                                    }
                                />
                            </svg>
                        </button>
                        <button
                            onClick={() => onEdit(slide)}
                            className="p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                            title="Edit"
                        >
                            <svg
                                className="w-5 h-5"
                                fill="none"
                                stroke="currentColor"
                                viewBox="0 0 24 24"
                            >
                                <path
                                    strokeLinecap="round"
                                    strokeLinejoin="round"
                                    strokeWidth="2"
                                    d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"
                                />
                            </svg>
                        </button>
                        <button
                            onClick={() => onDelete(slide.id)}
                            className="p-2 text-gray-600 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                            title="Delete"
                        >
                            <svg
                                className="w-5 h-5"
                                fill="none"
                                stroke="currentColor"
                                viewBox="0 0 24 24"
                            >
                                <path
                                    strokeLinecap="round"
                                    strokeLinejoin="round"
                                    strokeWidth="2"
                                    d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
                                />
                            </svg>
                        </button>
                    </div>
                </div>
            </div>
        </motion.div>
    );
};

export default AdminPage;
